// Calculate previous month date range
const now = new Date();
const reportDate = now.toISOString().split('T')[0];

const prevMonthEnd = new Date(now.getFullYear(), now.getMonth(), 0);
const prevMonthStart = new Date(now.getFullYear(), now.getMonth() - 1, 1);

const fmt = (d) => d.toISOString().split('T')[0];
const monthLabel = prevMonthStart.toLocaleString('en-US', { month: 'long', year: 'numeric' });

return [{ json: {
  reportDate,
  monthStart: fmt(prevMonthStart),
  monthEnd: fmt(prevMonthEnd),
  monthLabel,
  nowIso: now.toISOString()
} }];

// Calculate ROI by marketing channel
const dates = $('Calculate Month Range').first().json;
const revenueRaw = $('Fetch Revenue by Source').first().json;
const adsRaw = $('Fetch Google Ads Spend').first().json;
const leadsRaw = $('Fetch Leads by Source').first().json;

const revenue = Array.isArray(revenueRaw.body) ? revenueRaw.body : (Array.isArray(revenueRaw) ? revenueRaw : []);
const ads = Array.isArray(adsRaw.body) ? adsRaw.body : (Array.isArray(adsRaw) ? adsRaw : []);
const leads = Array.isArray(leadsRaw.body) ? leadsRaw.body : (Array.isArray(leadsRaw) ? leadsRaw : []);

// Canonical channel mapping
function normalizeChannel(src) {
  if (!src) return 'unknown';
  const s = src.toLowerCase().trim();
  if (s.includes('google') && (s.includes('ad') || s.includes('paid') || s.includes('cpc'))) return 'google_ads';
  if (s.includes('google') || s.includes('organic')) return 'google_organic';
  if (s.includes('referral') || s.includes('refer')) return 'referral';
  if (s.includes('nextdoor')) return 'nextdoor';
  if (s.includes('facebook') || s.includes('fb') || s.includes('meta')) return 'facebook';
  if (s.includes('yard') || s.includes('sign')) return 'yard_sign';
  if (s.includes('direct') || s.includes('phone') || s.includes('walk')) return 'direct';
  return s;
}

// Aggregate revenue by channel
const channels = {};
const channelOrder = ['google_organic', 'google_ads', 'referral', 'direct', 'nextdoor', 'facebook', 'yard_sign'];
for (const ch of channelOrder) {
  channels[ch] = { revenue: 0, jobs: 0, leads: 0, bookedLeads: 0, cost: 0 };
}

for (const r of revenue) {
  const ch = normalizeChannel(r.lead_source);
  if (!channels[ch]) channels[ch] = { revenue: 0, jobs: 0, leads: 0, bookedLeads: 0, cost: 0 };
  channels[ch].revenue += parseFloat(r.revenue) || 0;
  channels[ch].jobs += 1;
}

// Aggregate ad spend
let totalAdSpend = 0;
for (const a of ads) {
  const spend = parseFloat(a.spend) || 0;
  totalAdSpend += spend;
}
if (channels['google_ads']) channels['google_ads'].cost = totalAdSpend;

// Aggregate leads by channel
for (const l of leads) {
  const ch = normalizeChannel(l.source);
  if (!channels[ch]) channels[ch] = { revenue: 0, jobs: 0, leads: 0, bookedLeads: 0, cost: 0 };
  channels[ch].leads += 1;
  if (l.status === 'booked' || l.status === 'completed') {
    channels[ch].bookedLeads += 1;
  }
}

// Calculate per-channel metrics
const fmt = (n, d) => Number(n).toLocaleString('en-US', { minimumFractionDigits: d || 0, maximumFractionDigits: d || 0 });
const channelResults = [];
let totalRevenue = 0;
let totalLeads = 0;
let totalCost = 0;

for (const [ch, data] of Object.entries(channels)) {
  const roi = data.cost > 0 ? Math.round(((data.revenue - data.cost) / data.cost) * 10000) / 100 : (data.revenue > 0 ? Infinity : 0);
  const costPerLead = data.leads > 0 && data.cost > 0 ? Math.round((data.cost / data.leads) * 100) / 100 : 0;
  const conversionRate = data.leads > 0 ? Math.round((data.bookedLeads / data.leads) * 10000) / 100 : 0;

  totalRevenue += data.revenue;
  totalLeads += data.leads;
  totalCost += data.cost;

  channelResults.push({
    channel: ch,
    revenue: Math.round(data.revenue * 100) / 100,
    cost: Math.round(data.cost * 100) / 100,
    roi_pct: roi === Infinity ? 999 : roi,
    leads: data.leads,
    booked: data.bookedLeads,
    jobs: data.jobs,
    cost_per_lead: costPerLead,
    conversion_rate: conversionRate
  });
}

channelResults.sort((a, b) => b.revenue - a.revenue);

// Overall ROI
const overallROI = totalCost > 0 ? Math.round(((totalRevenue - totalCost) / totalCost) * 100) : (totalRevenue > 0 ? 999 : 0);

// Build sections for TG-118
const topMetrics = [
  { label: 'Total Revenue', value: '$' + fmt(totalRevenue, 2), change: '' },
  { label: 'Total Ad Spend', value: '$' + fmt(totalCost, 2), change: '' },
  { label: 'Overall ROI', value: overallROI + '%', change: '' },
  { label: 'Total Leads', value: fmt(totalLeads), change: '' }
];

const tableHeaders = ['Channel', 'Revenue', 'Cost', 'ROI %', 'Leads', 'Cost/Lead', 'Conv Rate'];
const tableRows = channelResults.map(c => [
  c.channel.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase()),
  '$' + fmt(c.revenue, 2),
  c.cost > 0 ? '$' + fmt(c.cost, 2) : '$0',
  c.roi_pct >= 999 ? 'organic' : c.roi_pct + '%',
  c.leads.toString(),
  c.cost_per_lead > 0 ? '$' + fmt(c.cost_per_lead, 2) : '$0',
  c.conversion_rate + '%'
]);

const highlights = [];
const topChannel = channelResults[0];
if (topChannel && topChannel.revenue > 0) {
  highlights.push('Top channel: ' + topChannel.channel.replace(/_/g, ' ') + ' with $' + fmt(topChannel.revenue, 2) + ' revenue');
}
const paidChannels = channelResults.filter(c => c.cost > 0);
if (paidChannels.length > 0) {
  const bestPaidROI = paidChannels.sort((a, b) => b.roi_pct - a.roi_pct)[0];
  highlights.push('Best paid ROI: ' + bestPaidROI.channel.replace(/_/g, ' ') + ' at ' + bestPaidROI.roi_pct + '% return');
}
const organicChannels = channelResults.filter(c => c.cost === 0 && c.revenue > 0);
if (organicChannels.length > 0) {
  const organicRev = organicChannels.reduce((s, c) => s + c.revenue, 0);
  highlights.push('Organic channels generated $' + fmt(organicRev, 2) + ' at zero cost');
}
if (highlights.length === 0) {
  highlights.push('Channel ROI analysis active \u2014 data will populate as revenue flows in');
}

const actions = [];
if (paidChannels.length > 0) {
  const worstPaid = paidChannels.sort((a, b) => a.roi_pct - b.roi_pct)[0];
  if (worstPaid.roi_pct < 100) {
    actions.push('Review ' + worstPaid.channel.replace(/_/g, ' ') + ' spend \u2014 ROI at ' + worstPaid.roi_pct + '% is below breakeven');
  }
}
if (organicChannels.length > 0) {
  const topOrganic = organicChannels.sort((a, b) => b.revenue - a.revenue)[0];
  actions.push('Invest more in ' + topOrganic.channel.replace(/_/g, ' ') + ' \u2014 highest organic ROI at $' + fmt(topOrganic.revenue, 2));
}
const zeroLeadChannels = channelResults.filter(c => c.leads === 0 && channelOrder.includes(c.channel));
if (zeroLeadChannels.length > 0) {
  actions.push('No leads from: ' + zeroLeadChannels.map(c => c.channel.replace(/_/g, ' ')).join(', ') + ' \u2014 evaluate if these channels are worth pursuing');
}
if (actions.length === 0) {
  actions.push('All channels performing within expected ranges \u2014 continue current strategy');
}

const sections = [
  { type: 'metrics', title: 'Channel ROI Overview', items: topMetrics },
  { type: 'table', title: 'ROI by Channel', headers: tableHeaders, rows: tableRows },
  { type: 'highlights', title: 'Key Insights', items: highlights },
  { type: 'actions', title: 'Recommended Actions', items: actions }
];

return [{ json: {
  report_title: 'Monthly Channel ROI',
  report_subtitle: dates.monthLabel + ' | TotalGuard Marketing Intelligence',
  sections,
  storePayload: {
    report_type: 'channel_roi',
    report_date: dates.reportDate,
    report_data: {
      month: dates.monthLabel,
      total_revenue: Math.round(totalRevenue * 100) / 100,
      total_cost: Math.round(totalCost * 100) / 100,
      overall_roi_pct: overallROI,
      total_leads: totalLeads,
      channels: channelResults,
      highlights,
      actions
    },
    generated_by: 'TG-120'
  }
} }];
